12	type Item = { type: string };
13	type Step = { op: "quote"; items: Item[] };
14	type Scenario = { customer: { yearsWithMHPCO: number }; steps: Step[] };
15	
16	const COMPONENT_BLOCK_PRICE = 60;
17	const COMPONENT_TYPES = new Set(["rune"]);
18	
19	const sumBasePremiums = (items: Item[]): number => {
20	  const counts: Record<string, number> = {};
21	  for (const item of items) counts[item.type] = (counts[item.type] ?? 0) + 1;
22	  let total = 0;
23	  for (const [type, count] of Object.entries(counts)) {
24	    if (COMPONENT_TYPES.has(type) && count === 3) {
25	      total += COMPONENT_BLOCK_PRICE;
26	    } else {
27	      total += BASE_PREMIUM[type] * count;
28	    }
29	  }
30	  return total;
31	};
32	
33	const quotePremium = (items: Item[]): number => {
34	  const basePremium = sumBasePremiums(items);
35	  const firstInsurance = basePremium * FIRST_INSURANCE_RATE;
36	  return Math.ceil(basePremium + firstInsurance + PROCESSING_FEE);
37	};
38	
39	export const runScenario = (input: unknown): unknown => {
40	  const scenario = input as Scenario;
41	  const results = scenario.steps.map(({ items }) => ({ premium: quotePremium(items) }));
42	  return { results };
43	};
